  ('disabled-10ced7e2-moex-00062', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-114-d1a761c9', 'sub-disabled-10ced7e2-02', NULL, 'single_choice', '關於公務人員保障事件之再審議，下列敘述何者錯誤？', '["申請再審議，應自復審決定或再申訴決定確定時起 30 日之不變期間內 為之", "原行政處分、原管理措施、原工作條件之處置及原決定執行完畢後，不 得申請再審議", "再審議之申請，於公務人員保障暨培訓委員會作成決定前，得撤回之", "復審事件復審人已依法向司法機關請求救濟者，不得申請再審議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:49+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
