  ('disabled-10ced7e2-moex-00064', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-114-d1a761c9', 'sub-disabled-10ced7e2-02', NULL, 'single_choice', '關於政務官與事務官之區分，下列敘述何者錯誤？', '["政務官係經政治性任命，原則上無任用資格限制；事務官有法定之任用 資格限制，須經銓敘合格", "政務官與事務官均適用公務人員退休資遣撫卹法", "政務官之身分不受法律保障，應隨政黨更替或政策變更而得免職", "政務官與事務官均適用公務員懲戒法，但懲戒種類有別"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:49+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00065', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-114-d1a761c9', 'sub-disabled-10ced7e2-02', NULL, 'single_choice', '直轄市政府在自治事項範圍內與人民訂定行政契約時，關於行政院行使監 督權之敘述，下列何者正確？', '["行政院不得行使監督權", "行政院得為適法性監督與合目的性監督", "行政院僅得為適法性監督", "行政院僅得為合目的性監督"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:49+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00066', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-114-d1a761c9', 'sub-disabled-10ced7e2-02', NULL, 'single_choice', '下列何種情形，公務員仍保有公務員之身分？', '["公務員退休", "公務員留職停薪", "公務員辭職", "公務員遭撤職"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:49+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00067', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-114-d1a761c9', 'sub-disabled-10ced7e2-02', NULL, 'single_choice', '依據公務人員考績法規定，關於行政懲處之敘述，下列何者錯誤？', '["公務人員平時考核懲處分為申誡、記過、記大過", "平時考核獎懲不得互相抵銷", "專案考績一次記二大過者，免職", "考績應予免職人員，自確定之日起執行；未確定前，應先行停職"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:49+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00068', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-114-d1a761c9', 'sub-disabled-10ced7e2-02', NULL, 'single_choice', '關於公物之敘述，下列何者正確？', '["公物原則上得作為讓與、設定負擔等法律行為之標的物", "公物之所有權歸屬以行政主體所有為必要", "狹義之公物係指直接供行政或民眾使用之物", "騎樓通道雖為供公眾通行之用，但屬私有財產，並非公物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:49+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00069', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-114-d1a761c9', 'sub-disabled-10ced7e2-02', NULL, 'single_choice', '依行政程序法規定，關於行政命令之敘述，下列何者錯誤？', '["行政規則包括關於機關內部之組織、事務之分配、業務處理方式、人事 管理等一般性規定", "為協助下級機關或屬官統一解釋法令、認定事實而訂頒之解釋性規定為 行政規則", "為協助下級機關或屬官行使裁量權，而訂頒之裁量基準為法規命令", "無法律之授權而剝奪或限制人民之自由、權利之法規命令為無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:49+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL)
